import React from 'react';
import RichTextEditor from '../controls/RichTextEditor';

function CustomSectionsSection({ data, onUpdate }) {
  const sections = data || [];

  const addSection = () => {
    const newSection = { id: Date.now(), title: '', items: [''] };
    onUpdate([...(sections), newSection]);
  };

  const removeSection = (id) => {
    onUpdate(sections.filter(s => s.id !== id));
  };

  const updateSectionTitle = (id, title) => {
    onUpdate(sections.map(s => s.id === id ? { ...s, title } : s));
  };

  const updateItem = (sid, idx, html) => {
    onUpdate(sections.map(s => s.id === sid ? { ...s, items: s.items.map((it, i) => i === idx ? html : it) } : s));
  };

  const addItem = (sid) => {
    onUpdate(sections.map(s => s.id === sid ? { ...s, items: [...s.items, ''] } : s));
  };

  const removeItem = (sid, idx) => {
    onUpdate(sections.map(s => s.id === sid ? { ...s, items: s.items.filter((_, i) => i !== idx) } : s));
  };

  return (
    <section className="section active">
      <h2>Custom Sections</h2>
      <p className="section-description">Add your own sections like Achievements, Certifications, Publications, etc.</p>

      {(sections).map((sec, sIndex) => (
        <div key={sec.id} className="education-item">
          <h3>
            <input 
              type="text"
              className="form-control"
              placeholder="Section Title (e.g., Achievements)"
              value={sec.title}
              onChange={(e) => updateSectionTitle(sec.id, e.target.value)}
            />
            <div className="item-actions">
              <button type="button" className="btn btn--small btn--danger" onClick={() => removeSection(sec.id)}>Remove</button>
            </div>
          </h3>

          <div className="achievement-list">
            {sec.items.map((item, idx) => (
              <div key={idx} className="achievement-item" style={{ alignItems: 'stretch' }}>
                <div style={{ flex: 1 }}>
                  <RichTextEditor value={item} onChange={(html) => updateItem(sec.id, idx, html)} placeholder="Add content" />
                </div>
                <button type="button" className="btn btn--small btn--danger" onClick={() => removeItem(sec.id, idx)}>×</button>
              </div>
            ))}
            <button type="button" className="btn btn--small btn--outline" onClick={() => addItem(sec.id)}>+ Add Item</button>
          </div>
        </div>
      ))}

      <button className="btn btn--primary" onClick={addSection}>+ Add Section</button>
    </section>
  );
}

export default CustomSectionsSection;
